"use client";

import React from 'react';
import type { DictionaryWord } from './types';

export interface WordCardProps {
    word: DictionaryWord;
    className?: string;
}

/** A small pill badge — used internally for part-of-speech, exported in case you want it standalone. */
export function PartOfSpeechBadge({ children }: { children: React.ReactNode }) {
    return (
        <span
            style={{
                display: 'inline-block',
                padding: '0.2rem 0.6rem',
                fontSize: '0.65rem',
                fontWeight: 700,
                textTransform: 'uppercase',
                letterSpacing: '0.05em',
                borderRadius: 'var(--dui-radius, 9999px)',
                background: 'var(--dui-muted, rgba(127,127,127,0.15))',
                color: 'var(--dui-fg, currentColor)',
            }}
        >
            {children}
        </span>
    );
}

/** A word list card: word, pronunciation, part-of-speech badge, first definition.
 *  Renders as a plain `<a>` when `word.href` is set, a `<div>` otherwise. */
export default function WordCard({ word, className }: WordCardProps) {
    const Tag = word.href ? 'a' : 'div';
    return (
        <Tag
            href={word.href}
            className={className}
            style={{
                display: 'block',
                padding: '1.25rem',
                borderRadius: 'var(--dui-radius, 0.75rem)',
                border: '1px solid var(--dui-border, rgba(127,127,127,0.25))',
                textDecoration: 'none',
                color: 'inherit',
            }}
        >
            <div style={{ display: 'flex', alignItems: 'baseline', justifyContent: 'space-between', gap: '0.75rem', marginBottom: '0.35rem' }}>
                <h3 style={{ fontSize: '1.25rem', fontWeight: 800, margin: 0 }}>{word.word}</h3>
                {word.partOfSpeech && <PartOfSpeechBadge>{word.partOfSpeech}</PartOfSpeechBadge>}
            </div>
            {word.pronunciation && (
                <p style={{ fontSize: '0.85rem', opacity: 0.6, margin: '0 0 0.4rem' }}>{word.pronunciation}</p>
            )}
            {word.definitions[0] && (
                <p style={{ fontSize: '0.95rem', margin: 0, opacity: 0.9 }}>{word.definitions[0]}</p>
            )}
        </Tag>
    );
}

"use client";

import React from 'react';
import { Search } from 'lucide-react';

export interface SearchBoxProps {
    value: string;
    onChange: (value: string) => void;
    placeholder?: string;
    /** Result count to show as a hint, e.g. "42 words". Omit to hide. */
    resultCount?: number;
    className?: string;
}

/**
 * A controlled search input. Deliberately has no search engine baked in —
 * plug in whatever you filter/fuzzy-match with (Fuse.js, a server query,
 * plain `.includes()`) and pass the current text in via `value`/`onChange`.
 */
export default function SearchBox({ value, onChange, placeholder = 'Search…', resultCount, className }: SearchBoxProps) {
    return (
        <div className={className} style={{ position: 'relative' }}>
            <input
                type="text"
                value={value}
                onChange={(e) => onChange(e.target.value)}
                placeholder={placeholder}
                style={{
                    width: '100%',
                    padding: '0.75rem 2.75rem 0.75rem 1rem',
                    fontSize: '1rem',
                    borderRadius: 'var(--dui-radius, 0.5rem)',
                    border: '1.5px solid var(--dui-border, #ccc)',
                    background: 'var(--dui-bg, transparent)',
                    color: 'var(--dui-fg, currentColor)',
                    outline: 'none',
                }}
            />
            <Search
                size={18}
                style={{ position: 'absolute', right: '0.9rem', top: '50%', transform: 'translateY(-50%)', opacity: 0.6 }}
            />
            {resultCount !== undefined && (
                <p style={{ fontSize: '0.8rem', opacity: 0.6, marginTop: '0.5rem' }}>
                    {resultCount} {resultCount === 1 ? 'result' : 'results'}
                </p>
            )}
        </div>
    );
}

export interface DictionaryWord {
    word: string;
    pronunciation?: string;
    partOfSpeech?: string;
    /** Short definitions/glosses, first one used as the card's summary line. */
    definitions: string[];
    /** Link to the word's full detail page, if any. */
    href?: string;
}
